{
  "病情摘要": "患者2型糖尿病8年，当前血糖控制不佳（近2周空腹8.5-10.2 mmol/L，餐后12-15 mmol/L，HbA1c 8.6%）。关键异常为用药不规律（偶漏服晚餐前降糖药）、生活方式不佳（运动减少、晚餐主食偏多）及双足偶有麻木（提示周围神经病变可能）。稳定因素为血压控制尚可（132/78 mmHg），无急性并发症及严重不适症状。",
  "依从性": {
    "用药": "存在偶尔漏服晚餐前降糖药现象，直接影响血糖控制。建议设置手机闹钟或使用分装药盒提醒，切勿因漏服而自行加倍补服或更改剂量。",
    "饮食运动": "运动量因照顾孙子减少，且晚餐主食偏多，不符合糖尿病管理要求。建议调整饮食结构，控制晚餐主食量并增加蔬菜比例，利用碎片时间增加日常活动。",
    "复诊检查": "最近一次HbA1c 8.6%提示近3个月整体血糖控制不达标，需及时门诊复诊以评估并调整治疗方案。"
  },
  "居家监测": {
    "项目": [
      "空腹及餐后2小时血糖",
      "血压",
      "足部皮肤及感觉变化",
      "体重"
    ],
    "频率": "血糖建议每周监测2-3天（包含空腹和餐后2小时）；血压每周监测1-2次；足部每日检查。",
    "目标": "空腹血糖4.4-7.0 mmol/L，餐后2小时血糖<10.0 mmol/L，血压<130/80 mmHg（具体目标需遵医嘱个体化调整）。",
    "记录要求": "使用专用记录本或手机APP详细记录监测日期、时间、数值及饮食运动特殊情况，复诊时务必带给医护人员评估。"
  },
  "风险分层": {
    "级别": "中风险",
    "依据": [
      "血糖控制不佳（HbA1c 8.6%，空腹及餐后均明显超标）",
      "存在用药漏服及不良生活方式等可控危险因素",
      "双足偶有麻木，提示可能存在糖尿病周围神经病变，有足部溃疡潜在风险"
    ]
  },
  "随访建议": {
    "方式": "门诊复诊",
    "时间": "建议1-2周内前往内分泌科门诊复诊。",
    "护理措施": [
      "评估漏服原因，指导使用药盒或闹钟提高用药依从性",
      "指导糖尿病饮食原则，重点调整晚餐主食定量与粗细搭配",
      "建议每日进行30分钟中等强度有氧运动，可分散在餐后1小时进行",
      "指导每日足部检查，注意足部保暖，避免使用热水袋或暖宝宝直接烫脚以防烫伤"
    ]
  },
  "需就医/升级条件": [
    "出现低血糖症状（如心慌、手抖、出冷汗、饥饿感、头晕等），需立即测血糖并补充糖分，若未缓解立即就医",
    "足部出现破溃、水泡、红肿、发热或疼痛加剧",
    "出现视力突然模糊、胸闷、胸痛、气促、下肢严重水肿或尿量显著减少",
    "血糖持续>16.7 mmol/L或<3.9 mmol/L且自行处理无效"
  ],
  "健康教育": [
