  ]
}

{
  "病情摘要": "患者老年男性，CKD 3b期（eGFR 38），糖尿病肾病可能。当前肌酐较前略升高，血钾5.4 mmol/L提示高钾血症。容量负荷稳定，无明显水肿，尿量正常。高钾血症主要与不当的高钾饮食（香蕉、蔬菜汤）有关。降压药依从性良好。",
  "依从性": {
    "用药": "降压药按时服用，依从性良好。未提及降糖药及其他肾脏保护药物使用情况，需补充评估具体用药清单，特别是是否使用ACEI/ARB或保钾利尿剂。",
    "饮食运动": "存在严重饮食误区，每日食用香蕉及常喝蔬菜汤导致高钾摄入，对CKD高钾患者极其危险。未提及运动、戒烟限酒及限盐情况，需全面评估。",
    "复诊检查": "近期已进行肾功能和电解质化验，发现肌酐升高和高钾血症，需根据结果及时复诊调整方案。"
  },
  "居家监测": {
    "项目": [
      "血压",
      "血糖",
      "体重",
      "尿量",
      "下肢水肿情况"
    ],
    "频率": "血压每日早晚各1次；血糖根据降糖方案每日监测1-4次；体重每日晨起排便后空腹称量；尿量每日记录24小时总量。",
    "目标": "血压控制在130/80 mmHg以下（或遵医嘱个体化目标）；空腹血糖4.4-7.0 mmol/L，非空腹<10.0 mmol/L；体重每日波动不超过1kg。",
    "记录要求": "使用专用记录本详细记录上述指标及日期时间，复诊时务必携带供医护人员评估。"
  },
  "风险分层": {
    "级别": "中高风险",
    "依据": [
      "血钾5.4 mmol/L，存在高钾血症，有引发致命性心律失常的潜在风险",
      "肌酐较3个月前升高，提示肾功能存在恶化趋势",
      "患者存在严重的高钾饮食误区，持续摄入高钾食物"
    ]
  },
  "随访建议": {
    "方式": "立即升级医疗评估（针对高钾血症）结合门诊复诊",
    "时间": "建议今日或24小时内紧急就医复查血钾并处理；常规门诊复诊建议在1-2周内。",
    "护理措施": [
      "立即停止食用香蕉、蔬菜汤及其他高钾食物，指导正确的蔬菜烹饪方法（切块水煮后弃汤）",
      "核对当前降压药及其他用药清单，评估是否包含升高血钾的药物，交由医生决定是否调整",
      "指导优质低蛋白、糖尿病饮食，控制总热量",
      "密切观察患者有无心悸、乏力、四肢麻木等高钾血症早期症状"
    ]
  },
  "需就医/升级条件": [
    "出现心悸、胸闷、心跳不规则、严重乏力、肌肉酸痛、四肢或口周麻木（提示高钾血症加重）",
    "尿量突然显著减少（<400ml/日）或无尿",
    "出现明显水肿、呼吸困难、夜间不能平卧",
    "血糖持续>16.7 mmol/L或<3.9 mmol/L，或出现低血糖/高血糖昏迷先兆"
  ],
  "健康教育": [
    "纠正高钾饮食误区：明确告知CKD伴高钾血症患者严禁吃香蕉，避免橘子、橙子、土豆、蘑菇、紫菜等高钾食物；蔬菜必须水煮后弃汤食用，严禁喝菜汤",
    "饮食管理：坚持优质低蛋白饮食（如瘦肉、鱼、蛋、奶），配合糖尿病饮食原则，限制钠盐摄入（<5g/日）",
    "用药安全：绝对不自行服用中药、偏方、保健品或非处方止痛药（如NSAIDs），以免加重肾损伤或引起钾潴留",
    "症状识别：教育患者及家属识别高钾血症和心衰的早期红旗症状，一旦出现立即就医"
  ]
}

{
  "病情摘要": "81岁男性，2型糖尿病15年，基础胰岛素联合口服药治疗。近10天频发清晨低血糖（最低3.2 mmol/L），伴出汗、手抖，进食后缓解。存在晚餐进食减少但睡前胰岛素未调整的情况。近期体重下降2kg，白天独居较多。当前血糖控制不佳，存在极高的严重低血糖风险。",
  "依从性": {
    "用药": "晚餐进食减少时未调整睡前胰岛素剂量，导致药物与饮食不匹配，引发低血糖。建议尽快就医由医生调整胰岛素剂量，切勿自行停药或盲目减量。",
    "饮食运动": "晚餐进食不规律，近期体重下降2kg，提示营养摄入不足。需规律三餐，保证适量碳水化合物摄入，避免空腹时间过长。",
    "复诊检查": "近期频发低血糖及体重下降，需尽快门诊复诊，评估整体营养状态及调整降糖方案。"
  },
  "居家监测": {
    "项目": [
      "指尖血糖（空腹、睡前、凌晨3点）",
      "体重",
      "低血糖症状（出汗、手抖、心慌、饥饿等）"
    ],
    "频率": "血糖每日监测空腹、三餐后2小时及睡前，近期频发低血糖需加测凌晨3点血糖；体重每周测量1次。",
    "目标": "高龄患者血糖控制目标宜适当放宽，空腹血糖建议7.0-8.5 mmol/L，餐后2小时血糖8.0-11.0 mmol/L，以不发生低血糖为首要原则。体重需保持稳定。",
    "记录要求": "详细记录血糖值、测量时间、饮食情况、用药时间及低血糖发生时的处理过程，复诊时务必带给医生评估。"
  },
  "风险分层": {
    "级别": "高风险",
    "依据": [
      "高龄（81岁）",
      "频发严重低血糖（最低3.2 mmol/L）",
      "白天独居较多，低血糖发作时缺乏及时救助",
      "晚餐进食不规律且睡前胰岛素未调整",
      "近期体重下降2kg"
    ]
  },
  "随访建议": {
    "方式": "立即升级医疗评估（门诊复诊），后续结合电话随访",
    "时间": "建议1-2天内由家属陪同前往内分泌科门诊复诊；3天后进行电话随访评估调整效果。",
    "护理措施": [
      "指导家属或社区人员加强白天巡视与联系",
      "指导患者及家属正确使用快速升糖食物并掌握15-15原则",
      "强调晚餐规律进食及胰岛素注射与进食的匹配",
      "评估独居环境安全性及紧急呼叫设备"
    ]
  },
  "需就医/升级条件": [
    "血糖<3.9 mmol/L且进食后不缓解，或出现意识模糊、昏迷、抽搐等严重低血糖症状，立即呼叫120",
    "频繁发生低血糖（每周≥2次）",
    "体重持续下降或出现恶心、呕吐、呼吸带有烂苹果味等急性并发症征象"
  ],
  "健康教育": [
    "低血糖识别与急救：熟知低血糖症状，随身携带糖果或饼干，遵循‘15-15原则’（吃15g碳水，等15分钟复测血糖）",
    "饮食与用药匹配：强调定时定量进餐，若晚餐进食减少，需提前咨询医生调整胰岛素剂量，切忌‘吃得少但针照打’",
    "独居安全：建议安装紧急呼叫设备，白天保持与家属或社区网格员联系，告知邻居自己的病情及急救联系方式",
    "随身携带急救信息卡：写明姓名、疾病、用药、家属联系方式及低血糖急救提示"
  ]
}

{
  "病情摘要": "患者55岁女性，高血压10年合并慢性肾病2期及尿微量白蛋白升高。近1个月家庭血压控制不佳（145-155/85-92 mmHg），主要诱因为晚间降压药漏服及高盐饮食。目前无水肿，尿量正常，近期肌酐稳定，无急性靶器官损害表现。",
