{
  "病情摘要": "70岁男性，射血分数降低的心衰（HFrEF），近期容量负荷及心衰症状控制平稳（体重稳定、无水肿、无夜间憋醒、活动耐量可）。但出现晨起症状性低血压（92/58 mmHg伴体位性头晕）及心动过缓（58次/分），考虑与抗心衰药物相关。患者对多重用药存在顾虑，有自行停药倾向。",
  "依从性": {
    "用药": "目前规律服药，但出现药物相关不良反应（低血压、心动过缓）。患者有自行停药意愿，需重点干预，严禁自行停药或更改剂量。",
    "饮食运动": "可慢走20分钟，运动耐量尚可。未提及具体饮食（限盐、限水）执行情况，需补充评估。",
    "复诊检查": "未提及近期复诊和化验（如电解质、肾功能）情况，需补充评估。"
  },
  "居家监测": {
    "项目": [
      "血压（含卧位和立位）",
      "心率",
      "体重",
      "尿量",
      "心衰症状（呼吸困难、水肿、头晕）"
    ],
    "频率": "血压和心率每日早晚及头晕时测量（需测立位）；体重每日晨起排尿后；症状每日观察。",
    "目标": "血压需个体化，HFrEF患者耐受情况下收缩压尽量≥90mmHg，避免症状性低血压；静息心率目标通常在55-60次/分，但需结合血压耐受情况；体重波动<1kg/日或2kg/周。",
    "记录要求": "记录在专用本上，注明测量时间、体位（卧位/立位）、数值及伴随症状，复诊时带给医生评估。"
  },
  "风险分层": {
